Javascript.validate:
var description = Services.getValue(REF_DATA_XPATH + "/DismissalDetailsList/DismissalDetail[./Value = " + DismissalDetails.dataBinding + "]/Description");
var valueTest = Services.getValue( REF_DATA_XPATH + "/DismissalDetailsList/DismissalDetail[./Description = " + DismissalDetails.dataBinding + "]/Value" );
if (description == null && valueTest == null)
{
	// This is not a valid value - see list of Values
	return ErrorCode.getErrorCode("CaseMan_Reports_Invalid_LOV_Msg");
}
else
{
	return null;
}

Javascript.miscCode:
			
			DismissalDetails.initialise		= function() 
			{ 
				dom = getList("../LOV/DismissalDetailsList.xml"); 
				Services.addNode(dom, REF_DATA_XPATH);
				//alert(Services.getValue(REF_DATA_XPATH + "/DismissalDetailsList"));				
				return false; 
			}
			
			DismissalDetails.srcData 		= REF_DATA_XPATH + "/DismissalDetailsList";
			DismissalDetails.rowXPath 		= "DismissalDetail";
			DismissalDetails.keyXPath 		= "Description";
			
			function DismissalDetailsLOVGrid() {};
			DismissalDetailsLOVGrid.dataBinding = DismissalDetails.dataBinding;
			DismissalDetailsLOVGrid.srcData = REF_DATA_XPATH + "/DismissalDetailsList";
			DismissalDetailsLOVGrid.rowXPath = "DismissalDetail";
			DismissalDetailsLOVGrid.keyXPath = "Description";
			DismissalDetailsLOVGrid.columns = [
				{xpath: "Description"}
			];
			
			DismissalDetailsLOVGrid.raise = {
				eventBinding: {
					singleClicks: [ {element: "DismissalDetailsLOVButton"} ],
					keys: [ { key: Key.F6, element: "DismissalDetails" } ]
				}
			};
			
			function DismissalDetailsLOVButton() {}
			DismissalDetailsLOVButton.tabIndex = __tabIdx++;
